import argparse
import json
import pickle
from pathlib import Path
from collections import deque, defaultdict
import numpy as np
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist"}

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    # Find closest current node if exact match missing
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    # Build graph
    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = neighs
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def graph_distance(start, goal):
        if start == goal:
            return 0
        queue = deque([(start, 0)])
        seen = {start}
        while queue:
            curr, dist = queue.popleft()
            for neigh in graph.get(curr, []):
                if neigh not in seen:
                    if neigh == goal:
                        return dist + 1
                    seen.add(neigh)
                    queue.append((neigh, dist + 1))
        return float('inf')

    # Select best target by utility / (dist + 1)
    best_score = -1.0
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = graph_distance(current_pos, tcoord)
        if dist == float('inf') or dist == 0:
            continue
        score = util / (dist + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        # fallback: max utility neighbor
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    # Find next node on shortest path to best_target
    def find_next_on_path(start, goal):
        if start == goal:
            return start
        queue = deque([start])
        parent = {start: None}
        while queue:
            curr = queue.popleft()
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                if neigh not in parent:
                    parent[neigh] = curr
                    queue.append(neigh)
        if goal not in parent:
            return None
        # Trace back to find the next after start
        curr = goal
        while parent.get(curr) != start and parent.get(curr) is not None:
            curr = parent[curr]
        return curr

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        # fallback to local max utility
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    # Return the matching neighbor from obs["neighbors"]
    for neigh_raw in neighbors:
        if coord_to_tuple(neigh_raw) == next_coord:
            return neigh_raw
    return neighbors[0]

def run_evaluation(data_path, checkpoint, output_path):
    data_path = Path(data_path)
    model = load_model(checkpoint)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    eval_config_path = data_path / "eval_config.json"
    map_list = []
    if eval_config_path.exists():
        with open(eval_config_path, "r") as f:
            eval_config = json.load(f)
        map_list = eval_config.get("maps", [])
        if not map_list and "map_paths" in eval_config:
            for p in eval_config["map_paths"]:
                map_list.append({"map_path": p, "env_type": "unknown"})
    if not map_list:
        print("No eval_config.json or empty, using 2 training maps per type for local testing.")
        for env_type in ["room", "tunnel", "outdoor"]:
            map_dir = data_path / "maps_train" / env_type
            if map_dir.exists():
                maps_in_type = sorted(map_dir.glob("*.png"))[:2]
                for p in maps_in_type:
                    map_list.append({"map_path": str(p.relative_to(data_path) if str(data_path) in str(p) else str(p)), "env_type": env_type})
    print(f"Evaluating on {len(map_list)} maps.")

    per_episode = []
    explored_rates = []
    success_count = 0
    travel_dists_success = []
    total_episodes = len(map_list)

    for item in map_list:
        if isinstance(item, (str, dict)):
            if isinstance(item, str):
                map_path_str = item
                env_type = "unknown"
            else:
                map_path_str = item.get("map_path", str(item))
                env_type = item.get("env_type", "unknown")
        else:
            map_path_str = str(item)
            env_type = "unknown"
        if not Path(map_path_str).is_absolute():
            full_map_path = data_path / map_path_str
        else:
            full_map_path = Path(map_path_str)
        if not full_map_path.exists():
            print(f"Warning: Map not found {full_map_path}, skipping.")
            continue
        try:
            env = ExplorationEnv(map_path=str(full_map_path))
            obs = env.reset()
            done = False
            step_count = 0
            max_steps = 128
            while not done and step_count < max_steps:
                target = select_waypoint(obs, model)
                if target is None or len(obs.get("neighbors", [])) == 0:
                    break
                obs, info = env.step(target)
                done = info.get("done", False)
                step_count += 1
            metrics = env.get_metrics()
            explored = metrics.get("explored_rate", 0.0)
            travel = metrics.get("travel_distance", 0.0)
            success = 1 if explored > 0.9999 else 0
            per_episode.append({
                "map_path": map_path_str,
                "env_type": env_type,
                "success": success,
                "travel_distance": float(travel),
                "explored_rate": float(explored),
                "n_steps": int(step_count)
            })
            explored_rates.append(explored)
            if success:
                success_count += 1
                travel_dists_success.append(travel)
        except Exception as e:
            print(f"Error processing {map_path_str}: {str(e)}")
            per_episode.append({
                "map_path": map_path_str,
                "env_type": env_type,
                "success": 0,
                "travel_distance": 0.0,
                "explored_rate": 0.0,
                "n_steps": 0
            })
            explored_rates.append(0.0)

    explored_rate = float(np.mean(explored_rates)) if explored_rates else 0.0
    success_rate = float(success_count / total_episodes) if total_episodes > 0 else 0.0
    travel_distance = float(np.mean(travel_dists_success)) if travel_dists_success else 0.0

    per_type = defaultdict(lambda: {"explored_rates": [], "travels_success": [], "successes": []})
    for ep in per_episode:
        t = ep["env_type"]
        per_type[t]["explored_rates"].append(ep["explored_rate"])
        per_type[t]["successes"].append(ep["success"])
        if ep["success"]:
            per_type[t]["travels_success"].append(ep["travel_distance"])

    per_type_dict = {}
    for t, stats in per_type.items():
        mean_expl = np.mean(stats["explored_rates"]) if stats["explored_rates"] else 0.0
        n_succ = sum(stats["successes"])
        mean_succ = n_succ / len(stats["successes"]) if stats["successes"] else 0.0
        mean_dist = np.mean(stats["travels_success"]) if stats["travels_success"] else 0.0
        per_type_dict[t] = {
            "explored_rate": float(mean_expl),
            "travel_distance": float(mean_dist),
            "success_rate": float(mean_succ)
        }

    results = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type_dict,
        "total_episodes": total_episodes
    }

    with open(output_path, "w") as f:
        json.dump(results, f, indent=2)

    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate:.4f}, Avg dist: {travel_distance:.2f}")
    if success_rate > 0:
        proxy = success_rate * (300.0 / (travel_distance + 1e-6))
        print(f"Proxy exploration_score: {proxy:.4f}")
    print("Local test on train subset done.")
    return results

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
